const input = $input.first().json;
const body = input.body || input;

const product_name = body.product_name;
const image_url = body.image_url;
const marketplace = body.marketplace || 'WB';

if (!product_name) throw new Error('product_name is required');
if (!image_url) throw new Error('image_url is required');

return [{ json: {
  product_name: product_name,
  image_url: image_url,
  marketplace: marketplace,
  artikuls: body.artikuls || [],
  product_description: body.product_description || '',
  target_audience: body.target_audience || '',
  key_features: body.key_features || '',
  style: body.style || 'modern',
  color_scheme: body.color_scheme || 'auto',
  include_price: body.include_price || false,
  price: body.price || '',
  include_badge: body.include_badge || false,
  badge_text: body.badge_text || '',
  extra_instructions: body.extra_instructions || '',
  session_id: body.session_id || null,
  callback_url: body.callback_url || ''
}}];

const settings = {};
for (const row of $input.all()) {
  settings[row.json.key] = row.json.value;
}
const params = $('🔍 Валидация').first().json;

const systemPrompt = settings.ai_system_prompt || 'Ты — профессиональный дизайнер карточек товаров для маркетплейсов.';
const model = settings.ai_model || 'gpt-4o';
const baseUrl = (settings.ai_base_url || 'https://gptunnel.ru/v1').replace(/\/+$/, '');

return [{ json: { ...params, systemPrompt, model, baseUrl } }];

const ctx = $input.first().json;

const userPrompt = `Проанализируй изображение товара и создай подробный JSON с данными для карточки товара.

Товар: ${ctx.product_name}
Маркетплейс: ${ctx.marketplace}
Описание от продавца: ${ctx.product_description || 'нет'}
Целевая аудитория: ${ctx.target_audience || 'широкая'}
Ключевые особенности: ${ctx.key_features || 'определи по фото'}
Стиль дизайна: ${ctx.style}
Цветовая схема: ${ctx.color_scheme}
Дополнительные инструкции: ${ctx.extra_instructions || 'нет'}

НА ОСНОВЕ ФОТО ТОВАРА определи:
1. Категорию товара
2. Основные визуальные характеристики (цвет, форма, материал)
3. УТП (уникальное торговое предложение)
4. Эмоциональные триггеры для покупателя

Создай данные для ПРОДАЮЩЕЙ карточки. Ответ строго JSON:
{
  "main_title": "Яркий заголовок (3-5 слов, привлекающий внимание)",
  "subtitle": "Подзаголовок с ключевой выгодой",
  "bullet_points": ["5-7 коротких УТП/преимуществ с emoji"],
  "cta_text": "Призыв к действию",
  "seo_title": "SEO-заголовок для карточки",
  "seo_description": "SEO-описание 150-200 символов",
  "search_keywords": ["10-15 ключевых слов для поиска"],
  "category_suggestion": "Рекомендуемая категория на маркетплейсе",
  "color_palette": ["#hex1", "#hex2", "#hex3"],
  "visual_style_notes": "Рекомендации по визуальному оформлению",
  "rich_content_blocks": [
    {
      "type": "hero",
      "heading": "Главный блок с крупным фото",
      "text": "Описание для hero-блока"
    },
    {
      "type": "features",
      "heading": "Преимущества",
      "items": ["Пункт 1", "Пункт 2", "Пункт 3"]
    },
    {
      "type": "usage",
      "heading": "Как использовать",
      "steps": ["Шаг 1", "Шаг 2", "Шаг 3"]
    },
    {
      "type": "specs",
      "heading": "Характеристики",
      "items": {"Материал": "значение", "Размер": "значение"}
    }
  ],
  "infographic_prompts": [
    "Промпт для генерации инфографики слайда 1 (детальное описание на АНГЛИЙСКОМ для Seedream 3)",
    "Промпт для генерации инфографики слайда 2 (на АНГЛИЙСКОМ)",
    "Промпт для генерации инфографики слайда 3 (на АНГЛИЙСКОМ)"
  ],
  "a_plus_content": {
    "brand_story": "История бренда / миссия (2-3 предложения)",
    "comparison_table": {"columns": ["Наш товар", "Аналоги"], "rows": [["Преимущество 1", "Нет"]]}
  }
}`;

const messages = [
  { role: 'system', content: ctx.systemPrompt },
  {
    role: 'user',
    content: [
      { type: 'text', text: userPrompt },
      { type: 'image_url', image_url: { url: ctx.image_url, detail: 'high' } }
    ]
  }
];

const requestBody = JSON.stringify({
  model: ctx.model,
  messages: messages,
  max_tokens: 4000,
  temperature: 0.7
});

const url = ctx.baseUrl + '/chat/completions';

return [{ json: { url, body: requestBody, ...ctx } }];

const response = $input.first().json;
const prevCtx = $('🏗️ Запрос анализа фото').first().json;

let content = '';
try {
  content = response.choices[0].message.content;
} catch (e) {
  throw new Error('AI не вернул ответ: ' + JSON.stringify(response));
}

// Извлечь JSON из ответа
let cardData;
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    cardData = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('JSON не найден в ответе');
  }
} catch (e) {
  throw new Error('Ошибка парсинга JSON карточки: ' + e.message + ' | Raw: ' + content.substring(0, 500));
}

return [{ json: {
  product_name: prevCtx.product_name,
  image_url: prevCtx.image_url,
  marketplace: prevCtx.marketplace,
  artikuls: prevCtx.artikuls,
  session_id: prevCtx.session_id,
  callback_url: prevCtx.callback_url,
  style: prevCtx.style,
  color_scheme: prevCtx.color_scheme,
  include_price: prevCtx.include_price,
  price: prevCtx.price,
  include_badge: prevCtx.include_badge,
  badge_text: prevCtx.badge_text,
  card_data: cardData,
  baseUrl: prevCtx.baseUrl,
  raw_ai_response: content
}}];

const ctx = $input.first().json;
const cardData = ctx.card_data;
const prompts = cardData.infographic_prompts || [];

// Берём 1-й промпт или генерируем дефолтный
let mainPrompt = prompts[0]
  || 'Professional product infographic for ' + ctx.product_name + ' on marketplace ' + ctx.marketplace + '. ' + (cardData.visual_style_notes || 'Modern clean design') + '. Bright colors, clear layout, selling format, vertical orientation.';

// Убираем Midjourney-флаги (--ar, --v и т.д.) — Seedream принимает ar в теле запроса
mainPrompt = mainPrompt.replace(/\s*--[a-z]+\s+[\w:.]+/gi, '').trim();

return [{ json: {
  ...ctx,
  seedream_prompt: mainPrompt,
  all_infographic_prompts: prompts
}}];

const response = $input.first().json;
const ctx = $('🎨 Промпт Seedream').first().json;

if (response.code !== 0 && response.code !== undefined) {
  throw new Error('Seedream create failed: ' + JSON.stringify(response).substring(0, 500));
}

const taskId = response.id;
if (!taskId) throw new Error('Seedream did not return task_id: ' + JSON.stringify(response).substring(0, 300));

return [{ json: {
  task_id: taskId,
  media_base_url: ctx.baseUrl,
  session_id: ctx.session_id,
  product_name: ctx.product_name
}}];

const ctx = $('🔑 Извлечь task_id').first().json;
const statusResp = $input.first().json;

const status = (statusResp.status || '').toLowerCase();
if (status === 'fail' || status === 'failed' || status === 'error') {
  // Seedream не смог — продолжаем без инфографики
  return [{ json: {
    seedream_failed: true,
    seedream_error: JSON.stringify(statusResp).substring(0, 500),
    task_id: ctx.task_id,
    media_base_url: ctx.media_base_url
  }}];
}

let pollCount = 0;
try { pollCount = $('⏳ Ещё не готово').first().json.poll_count || 0; } catch(e) {}
pollCount++;

if (pollCount > 40) {
  return [{ json: {
    seedream_failed: true,
    seedream_error: 'Timeout after ' + (pollCount * 15) + ' seconds',
    task_id: ctx.task_id,
    media_base_url: ctx.media_base_url
  }}];
}

return [{ json: {
  task_id: ctx.task_id,
  media_base_url: ctx.media_base_url,
  poll_count: pollCount,
  seedream_failed: false
}}];

const statusResp = $input.first().json;
const ctx = $('🎨 Промпт Seedream').first().json;

// Поддержка: Seedream успех ИЛИ Seedream не смог (seedream_failed=true)
const seedreamFailed = statusResp.seedream_failed || false;
const imageUrl = statusResp.url || null;

if (!imageUrl && !seedreamFailed) {
  throw new Error('Seedream returned done but no URL: ' + JSON.stringify(statusResp).substring(0, 300));
}

const aPlusContent = {
  ...(ctx.card_data.a_plus_content || {}),
  infographic_url: imageUrl,
  seedream_task_id: statusResp.id || null
};

if (seedreamFailed) {
  aPlusContent.seedream_error = statusResp.seedream_error || 'Seedream generation failed';
}

return [{ json: {
  product_name: ctx.product_name,
  image_url: ctx.image_url,
  marketplace: ctx.marketplace,
  artikuls: ctx.artikuls,
  session_id: ctx.session_id,
  callback_url: ctx.callback_url,
  style: ctx.style,
  color_scheme: ctx.color_scheme,
  include_price: ctx.include_price,
  price: ctx.price,
  include_badge: ctx.include_badge,
  badge_text: ctx.badge_text,
  card_data: ctx.card_data,
  a_plus_content_merged: aPlusContent,
  infographic_url: imageUrl
}}];

const saved = $('💾 Сохранить карточку').first().json;
const infographicUrl = $('📎 Собрать результат').first().json.infographic_url || null;

return [{ json: {
  success: true,
  card_id: saved.id,
  product_name: saved.product_name,
  infographic_url: infographicUrl
}}];
